        // 任务①②：判断是否数字字符并提取值
        // 在这里补全代码...

        char ch2 = 'C';

        // 任务③：判断是否大写字母并转成小写
        // 在这里补全代码...
    }
}`}
      answerCode={`public class CharCheck {
    public static void main(String[] args) {
        char ch = '7';

        // 任务①②：判断是否数字字符（码值在 48~57 之间）并提取值
        if (ch >= '0' && ch <= '9') {
            int numValue = ch - '0';  // 提取数字值
            System.out.println(ch + " 是数字字符，对应整数值：" + numValue);
        } else {
