      </ListItem>
      <ListItem>
        <Text bold>char 参与运算结果是 int</Text>：<InlineCode>'a' + 1 = 98</InlineCode>（int），要得字符需 <InlineCode>(char)('a' + 1)</InlineCode>。
      </ListItem>
    </UnorderedList>
  </article>
);

